    body {
      background: radial-gradient(circle at 20% 30%, #0a0f1e, #020204);
      color: #d0f0ff;
      min-height: 100vh;
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 20px;
      position: relative;
      overflow-x: hidden;
    }

